init_eqs:
zoom_dec = 1;
rot_shader_dec = 0;
rot_shader = 0;
time_beat = 0;
rand_zoom = 1;
rand_rot = 0;
chaos_rand = 0;
//---DON'T TOUCH THIS ABOVE---

beat_trigger = 1.5;
time_delay = .25;
speed = 5;
chaos_val = 100;

frame_eqs:
dec = speed/fps;
time_beat += 1/fps;
//---DON'T MODIFY ABOVE---

if ((bass+treb)/2 > beat_trigger && time_beat > time_delay, beat=1; time_beat = 0, beat=0);

rand_zoom = if(beat, .25 + abs(rand(2)-.25), rand_zoom);
rand_rot = if(beat, $pi/4 - abs(rand(2)-0.4292), rand_rot);
chaos_neg_rand = if(beat, int(rand(2)), chaos_neg_rand);
chaos_neg = if (chaos_neg_rand, -1, 1);
chaos_rand = if(beat, rand(chaos_val)*chaos_neg, chaos_rand);

beat_smoothfall = if(beat, (bass+treb)/2, beat_smoothfall*=0.98);

//If these values are changes, it automatically smooths.
zoom = rand_zoom;
//rot = rand_rot;
rot_h = rand_rot;
//------------------------------------------------------

//Using Nitorami (martin)'s skills (smoothing).
zoom_dec = zoom_dec * (1-dec) + zoom * dec;
zoom = zoom_dec;
//rot_dec = rot_dec * (1-dec) + rot * dec;
rot_h_dec = rot_h_dec * (1-dec) + rot_h * dec;
//rot = rot_h_dec;

q1 = rot_h_dec;
q2 = chaos_rand;
q3 = beat_smoothfall*3.75;
